#!/usr/bin/env python3
"""Census of requests-specific references across shipped code + assert wrapper translation totality."""
import json, re, subprocess, sys
from pathlib import Path

ROOT = Path(subprocess.check_output(["git", "rev-parse", "--show-toplevel"], text=True).strip())
BASE_WRAPPER = "datadog_checks_base/datadog_checks/base/utils/http.py"
EXEMPT = ("datadog_checks_base/", "datadog_checks_dev/", "ddev/", ".ddev/")

files = subprocess.check_output(["git", "ls-files", "*.py"], text=True, cwd=ROOT).splitlines()

PATTERNS = {
    "except_qualified": re.compile(r"except\b[^\n]*requests\.exceptions"),
    "from_requests": re.compile(r"^\s*from\s+requests(\.|\s+import)"),
    "import_requests": re.compile(r"^\s*import\s+requests(\s|$|\.)"),
    "requests_attr": re.compile(r"\brequests\.[A-Za-z_]"),
    "session_access": re.compile(r"self\.http\._?session\b"),
    "authbase": re.compile(r"\bAuthBase\b"),
    "requests_response_build": re.compile(r"requests\.Response\("),
    "session_patch": re.compile(r"requests\.Session"),
}

census = {}
for f in files:
    if f == BASE_WRAPPER:
        continue
    shipped = not f.startswith(EXEMPT)
    text = (ROOT / f).read_text(errors="replace")
    hits = {}
    for name, pat in PATTERNS.items():
        c = sum(1 for ln in text.splitlines() if not ln.strip().startswith("#") and pat.search(ln))
        if c:
            hits[name] = c
    if hits:
        census[f] = {"shipped": shipped, "test": "/tests/" in f, "integration": f.split("/", 1)[0], "hits": hits}

(ROOT / ".r2").mkdir(exist_ok=True)
(ROOT / ".r2/httpx_census.json").write_text(json.dumps(census, indent=2, sort_keys=True))

wrapper = (ROOT / BASE_WRAPPER).read_text()
if not re.search(r"except\s+requests_exceptions\.RequestException", wrapper):
    print("FAIL: base wrapper does not catch requests_exceptions.RequestException (translation not total)")
    sys.exit(1)

shipped = [f for f in census if census[f]["shipped"]]
by_int = {}
for f in shipped:
    by_int[census[f]["integration"]] = by_int.get(census[f]["integration"], 0) + 1
print(f"requests-ref files: total={len(census)} shipped={len(shipped)}")
print(f"shipped integrations touched: {len(by_int)}")
print("translation totality: OK (wrapper catches RequestException base)")
sys.exit(0)

