#!/usr/bin/env python3
"""Committed, reproducible census of ``requests``-specific references.

This tool backs the httpx-agnosticization effort (RFC HTTPX). It scans every
git-tracked ``*.py`` file, classifies ``requests``-specific references into the
kill-list categories, tags each hit with its owning integration and whether the
file is shipped (vs. dev/harness exempt) and test (vs. production), and writes a
deterministic snapshot to ``.r2/httpx_census.json``.

It also enforces the *translation-totality* invariant: every ``requests``
exception referenced anywhere in the tree must descend from
``requests.exceptions.RequestException``. That is the static guarantee that a
single catch of ``RequestException`` at the base wrapper boundary translates
*every* requests error into an agnostic type. If any referenced requests
exception did not descend from ``RequestException`` (i.e. catching it would not
be total), the script exits non-zero, flagging a translation gap.

Usage::

    python .r2/httpx_census.py            # regenerate snapshot + run the gate
    python .r2/httpx_census.py --check     # verify the committed snapshot is current

Exit codes: 0 on success, 1 on a translation gap, 2 on snapshot drift (--check).
"""

from __future__ import annotations

import argparse
import json
import re
import subprocess
import sys
from pathlib import Path

import requests
from requests import exceptions as requests_exceptions

REPO_ROOT = Path(__file__).resolve().parent.parent
SNAPSHOT_PATH = REPO_ROOT / ".r2" / "httpx_census.json"

# Exempt roots: shared base library, the dev toolkit, and the ddev CLI / config.
# References here are infrastructure or harness code, not shipped integration code.
EXEMPT_PREFIXES: tuple[str, ...] = (
    "datadog_checks_base/",
    "datadog_checks_dev/",
    "ddev/",
    ".ddev/",
)

# The base wrapper itself owns the requests->agnostic translation; it is the
# subject of the invariant, never a census target.
BASE_WRAPPER = "datadog_checks_base/datadog_checks/base/utils/http.py"

# Category name -> compiled regex matched against comment-stripped source lines.
# A single line may match multiple categories; each match is recorded once per
# category.
CATEGORY_PATTERNS: dict[str, re.Pattern[str]] = {
    "except_requests_exceptions": re.compile(r"except\b.*\brequests\.exceptions\b"),
    "import_requests": re.compile(r"^\s*(?:from\s+requests\b|import\s+requests\b)"),
    "requests_attr": re.compile(r"\brequests\.\w+"),
    "http_session_access": re.compile(r"\bself\.http\._?session\b"),
    "authbase_subclass": re.compile(r"\bclass\s+\w+\s*\([^)]*\bAuthBase\b"),
    "requests_response_construction": re.compile(r"\brequests\.Response\s*\("),
    "requests_session_patch": re.compile(r"\brequests\.(?:sessions\.)?Session\b"),
}

# Patterns used to harvest referenced requests-exception *names* for the gate.
_EXC_QUALIFIED = re.compile(r"\brequests\.exceptions\.(\w+)")
_EXC_FROM_EXCEPTIONS = re.compile(r"\bfrom\s+requests\.exceptions\s+import\s+([^\n#]+)")
_EXC_FROM_REQUESTS = re.compile(r"\bfrom\s+requests\s+import\s+([^\n#]+)")
_EXC_TOP_LEVEL = re.compile(r"\brequests\.([A-Z]\w+)")


def _git_tracked_python_files() -> list[str]:
    out = subprocess.run(
        ["git", "ls-files", "*.py"],
        cwd=REPO_ROOT,
        capture_output=True,
        text=True,
        check=True,
    )
    return sorted(line for line in out.stdout.splitlines() if line)


def strip_comments(line: str) -> str:
    """Remove a trailing ``#`` comment, honoring simple quoting.

    Not a full tokenizer, but string-aware enough to avoid treating ``#`` inside
    single/double-quoted literals as a comment start.
    """
    in_single = in_double = False
    for i, ch in enumerate(line):
        if ch == "'" and not in_double:
            in_single = not in_single
        elif ch == '"' and not in_single:
            in_double = not in_double
        elif ch == "#" and not in_single and not in_double:
            return line[:i]
    return line


def integration_of(path: str) -> str:
    return path.split("/", 1)[0]


def is_exempt(path: str) -> bool:
    return path.startswith(EXEMPT_PREFIXES)


def is_test(path: str) -> bool:
    return "tests" in path.split("/")


def classify_line(text: str) -> list[str]:
    return [name for name, pattern in CATEGORY_PATTERNS.items() if pattern.search(text)]


def _split_import_names(clause: str) -> list[str]:
    clause = clause.split(" as ")[0]
    clause = clause.strip().strip("()")
    return [part.strip() for part in clause.split(",") if part.strip()]


def collect_exception_names(text: str) -> set[str]:
    """Harvest requests-exception identifiers referenced on a source line."""
    names: set[str] = set()
    names.update(_EXC_QUALIFIED.findall(text))
    for clause in _EXC_FROM_EXCEPTIONS.findall(text):
        for part in _split_import_names(clause):
            for name in part.split(" as "):
                names.add(name.strip())
    for clause in _EXC_FROM_REQUESTS.findall(text):
        for part in _split_import_names(clause):
            names.add(part.split(" as ")[0].strip())
    names.update(_EXC_TOP_LEVEL.findall(text))
    return {n for n in names if n and n.isidentifier()}


def build_census() -> tuple[dict[str, dict], set[str]]:
    """Return (files_snapshot, referenced_exception_names)."""
    files: dict[str, dict] = {}
    referenced: set[str] = set()

    for path in _git_tracked_python_files():
        if path == BASE_WRAPPER:
            continue
        abs_path = REPO_ROOT / path
        try:
            raw = abs_path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            continue

        hits: list[dict] = []
        for lineno, raw_line in enumerate(raw.splitlines(), start=1):
            code = strip_comments(raw_line)
            if "requests" not in code and "AuthBase" not in code:
                continue
            referenced |= collect_exception_names(code)
            for category in classify_line(code):
                hits.append(
                    {"line": lineno, "category": category, "text": raw_line.strip()}
                )

        if not hits:
            continue

        hits.sort(key=lambda h: (h["line"], h["category"]))
        files[path] = {
            "shipped": not is_exempt(path),
            "test": is_test(path),
            "integration": integration_of(path),
            "hits": hits,
        }

    return dict(sorted(files.items())), referenced


def build_snapshot() -> dict:
    files, referenced = build_census()
    shipped_files = {p: m for p, m in files.items() if m["shipped"]}
    shipped_integrations = sorted(
        {m["integration"] for m in shipped_files.values()}
    )

    category_totals: dict[str, int] = {name: 0 for name in CATEGORY_PATTERNS}
    for meta in files.values():
        for hit in meta["hits"]:
            category_totals[hit["category"]] += 1

    return {
        "summary": {
            "total_ref_files": len(files),
            "shipped_ref_files": len(shipped_files),
            "shipped_integrations_touched": len(shipped_integrations),
            "category_totals": dict(sorted(category_totals.items())),
            "referenced_requests_exceptions": sorted(referenced),
        },
        "shipped_integrations": shipped_integrations,
        "files": files,
    }


def _resolve_exception(name: str) -> type | None:
    obj = getattr(requests_exceptions, name, None) or getattr(requests, name, None)
    if isinstance(obj, type) and issubclass(obj, BaseException):
        return obj
    return None


def assert_translation_totality(referenced: list[str]) -> bool:
    """Verify catching ``RequestException`` is total over referenced exceptions.

    The base wrapper's translation path (``_translate_http_errors`` /
    ``_translate_requests_exception``) catches ``requests.exceptions.RequestException``.
    Because every concrete requests error descends from it, that single catch maps
    every requests error to an agnostic type. This gate proves the precondition
    against the installed requests version: it fails if any referenced requests
    exception does not descend from ``RequestException`` (a translation gap).
    """
    base = requests_exceptions.RequestException
    checked: list[str] = []
    gaps: list[str] = []
    for name in referenced:
        exc = _resolve_exception(name)
        if exc is None:
            continue
        checked.append(name)
        if not issubclass(exc, base):
            gaps.append(name)

    if gaps:
        print(
            "TRANSLATION GAP: referenced requests exceptions not covered by "
            f"RequestException: {sorted(gaps)}",
            file=sys.stderr,
        )
        return False

    print(
        f"translation totality OK: catching requests.exceptions.RequestException "
        f"covers all {len(checked)} referenced requests exception(s)"
    )
    return True


def print_summary(snapshot: dict) -> None:
    s = snapshot["summary"]
    print(f"total ref-files:              {s['total_ref_files']}")
    print(f"shipped ref-files:            {s['shipped_ref_files']}")
    print(f"shipped integrations touched: {s['shipped_integrations_touched']}")


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__.split("\n", 1)[0])
    parser.add_argument(
        "--check",
        action="store_true",
        help="verify the committed snapshot matches a fresh scan (no write)",
    )
    args = parser.parse_args(argv)

    snapshot = build_snapshot()
    serialized = json.dumps(snapshot, indent=2, sort_keys=True) + "\n"

    if args.check:
        if not SNAPSHOT_PATH.exists():
            print(f"missing snapshot: {SNAPSHOT_PATH}", file=sys.stderr)
            return 2
        current = SNAPSHOT_PATH.read_text(encoding="utf-8")
        if current != serialized:
            print(
                "snapshot drift: re-run `python .r2/httpx_census.py` and commit",
                file=sys.stderr,
            )
            return 2
    else:
        SNAPSHOT_PATH.parent.mkdir(parents=True, exist_ok=True)
        SNAPSHOT_PATH.write_text(serialized, encoding="utf-8")

    print_summary(snapshot)
    if not assert_translation_totality(snapshot["summary"]["referenced_requests_exceptions"]):
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

